import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.Vng7Hdlh.js";const c=JSON.parse('{"title":"19. トラブルシューティング","description":"","frontmatter":{},"headers":[],"relativePath":"tenant/19-troubleshoot.md","filePath":"tenant/19-troubleshoot.md"}'),h={name:"tenant/19-troubleshoot.md"};function l(i,t,o,n,b,s){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_19-トラブルシューティング" tabindex="-1">19. トラブルシューティング <a class="header-anchor" href="#_19-トラブルシューティング" aria-label="Permalink to &quot;19. トラブルシューティング&quot;">​</a></h1><p>よくある問題と対処法をまとめています。</p><h2 id="_19-1-ログイン関連" tabindex="-1">19.1 ログイン関連 <a class="header-anchor" href="#_19-1-ログイン関連" aria-label="Permalink to &quot;19.1 ログイン関連&quot;">​</a></h2><h3 id="ログインできない" tabindex="-1">ログインできない <a class="header-anchor" href="#ログインできない" aria-label="Permalink to &quot;ログインできない&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>「ユーザー名またはパスワードが正しくありません」</td><td>入力ミス</td><td>大文字/小文字を確認。ユーザー名は全て小文字の場合が多い</td></tr><tr><td>「このアカウントは無効化されています」</td><td>アカウント無効化</td><td>オーナーまたはマネージャーに連絡してアカウントを有効化してもらう</td></tr><tr><td>「このテナントは無効化されています」</td><td>テナント自体が無効</td><td>POSLA運営に連絡</td></tr><tr><td>「通信エラーが発生しました」</td><td>インターネット未接続</td><td>Wi-Fi/モバイル通信を確認して再試行</td></tr><tr><td>「サーバーが空のレスポンスを返しました」</td><td>サーバー障害</td><td>しばらく待って再試行。繰り返す場合はPOSLA運営に連絡</td></tr></tbody></table><h3 id="セッションが頻繁に切れる" tabindex="-1">セッションが頻繁に切れる <a class="header-anchor" href="#セッションが頻繁に切れる" aria-label="Permalink to &quot;セッションが頻繁に切れる&quot;">​</a></h3><ul><li>25分間操作がないとタイムアウト警告が表示されます</li><li>30分で自動ログアウトされます</li><li>ブラウザのクッキーを削除した場合もログアウトされます</li><li>解決策：操作を継続するか、警告が出たら「操作を続ける」ボタンを押す</li></ul><hr><h2 id="_19-2-注文関連" tabindex="-1">19.2 注文関連 <a class="header-anchor" href="#_19-2-注文関連" aria-label="Permalink to &quot;19.2 注文関連&quot;">​</a></h2><h3 id="セルフオーダーで注文できない" tabindex="-1">セルフオーダーで注文できない <a class="header-anchor" href="#セルフオーダーで注文できない" aria-label="Permalink to &quot;セルフオーダーで注文できない&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>「注文する」ボタンが無効</td><td>ラストオーダー中</td><td>マネージャーがラストオーダーを解除する（フロアマップの「LO解除」）</td></tr><tr><td>QRコードを読み取れない</td><td>QRコードが古い</td><td>管理ダッシュボードで新しいQRコードを生成・印刷</td></tr><tr><td>「品切れの品目が含まれています」</td><td>カート内品目が品切れ</td><td>該当品目をカートから削除して再送信</td></tr><tr><td>画面が真っ白</td><td>セッショントークン期限切れ</td><td>テーブルのセッショントークンが更新されている。新しいQRコードを使用</td></tr></tbody></table><h3 id="ハンディposで注文が送信されない" tabindex="-1">ハンディPOSで注文が送信されない <a class="header-anchor" href="#ハンディposで注文が送信されない" aria-label="Permalink to &quot;ハンディPOSで注文が送信されない&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>「カートが空です」</td><td>カートに品目がない</td><td>メニューから品目を選択してカートに追加</td></tr><tr><td>「テーブルを選択してください」</td><td>テーブル未選択</td><td>ドロップダウンからテーブルを選択</td></tr><tr><td>通信エラー</td><td>ネットワーク問題</td><td>Wi-Fi接続を確認。安定した接続を確保</td></tr></tbody></table><hr><h2 id="_19-3-kds関連" tabindex="-1">19.3 KDS関連 <a class="header-anchor" href="#_19-3-kds関連" aria-label="Permalink to &quot;19.3 KDS関連&quot;">​</a></h2><h3 id="kdsに注文が表示されない" tabindex="-1">KDSに注文が表示されない <a class="header-anchor" href="#kdsに注文が表示されない" aria-label="Permalink to &quot;KDSに注文が表示されない&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>全く注文が表示されない</td><td>ステーション選択の問題</td><td>「全品目」ボタンを選択して確認</td></tr><tr><td>一部の品目だけ表示されない</td><td>ステーションのカテゴリ割当</td><td>店舗設定でステーションの担当カテゴリを確認</td></tr><tr><td>更新が遅い</td><td>ポーリング</td><td>3秒間隔で自動更新されます。手動更新はありません</td></tr><tr><td>音が鳴らない</td><td>音声未許可</td><td>KDS起動時の「タップして開始」を確実に行う</td></tr></tbody></table><hr><h2 id="_19-4-会計・レジ関連" tabindex="-1">19.4 会計・レジ関連 <a class="header-anchor" href="#_19-4-会計・レジ関連" aria-label="Permalink to &quot;19.4 会計・レジ関連&quot;">​</a></h2><h3 id="レジで会計できない" tabindex="-1">レジで会計できない <a class="header-anchor" href="#レジで会計できない" aria-label="Permalink to &quot;レジで会計できない&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>会計待ちテーブルが表示されない</td><td>未会計の注文がない</td><td>注文が入っているか確認</td></tr><tr><td>「会計する」ボタンが押せない</td><td>処理中</td><td>二重押し防止。しばらく待つ</td></tr><tr><td>カードリーダーが接続できない</td><td>Stripe Terminal問題</td><td>「再検出」ボタンで再接続。端末の電源を確認</td></tr></tbody></table><h3 id="レジの過不足が大きい" tabindex="-1">レジの過不足が大きい <a class="header-anchor" href="#レジの過不足が大きい" aria-label="Permalink to &quot;レジの過不足が大きい&quot;">​</a></h3><ul><li>レジレポートでキャッシュログを確認し、入金・出金の記録漏れがないか確認</li><li>出金を記録せずに現金を取り出していないか確認</li><li>閾値（デフォルト¥500）を超える過不足は自動で警告表示されます</li></ul><hr><h2 id="_19-5-ネットワーク関連" tabindex="-1">19.5 ネットワーク関連 <a class="header-anchor" href="#_19-5-ネットワーク関連" aria-label="Permalink to &quot;19.5 ネットワーク関連&quot;">​</a></h2><h3 id="オフライン警告が表示される" tabindex="-1">オフライン警告が表示される <a class="header-anchor" href="#オフライン警告が表示される" aria-label="Permalink to &quot;オフライン警告が表示される&quot;">​</a></h3><p>POSLAはクラウド型システムのため、常時インターネット接続が必要です。</p><ul><li>画面上部に赤いバナーで「オフライン」警告が表示されます</li><li>オフライン中は新規注文の送信やデータ取得ができません</li><li>接続が復旧すると自動的に緑のバナーが表示され、通常動作に戻ります</li></ul><p><strong>対処法：</strong></p><ol><li>Wi-Fiルーターの状態を確認</li><li>モバイル通信に切り替えて試す</li><li>有線LAN接続を検討（安定性向上）</li><li>バックアップ用のモバイルルーターを準備</li></ol><h3 id="セルフオーダーの注文がオフライン時に保留される" tabindex="-1">セルフオーダーの注文がオフライン時に保留される <a class="header-anchor" href="#セルフオーダーの注文がオフライン時に保留される" aria-label="Permalink to &quot;セルフオーダーの注文がオフライン時に保留される&quot;">​</a></h3><p>お客さんのスマートフォンがオフラインの場合、注文はブラウザに保留されます。接続が復旧すると自動的に送信されます。24時間以上経過した保留注文は自動破棄されます。</p><hr><h2 id="_19-6-メニュー関連" tabindex="-1">19.6 メニュー関連 <a class="header-anchor" href="#_19-6-メニュー関連" aria-label="Permalink to &quot;19.6 メニュー関連&quot;">​</a></h2><h3 id="メニュー変更が反映されない" tabindex="-1">メニュー変更が反映されない <a class="header-anchor" href="#メニュー変更が反映されない" aria-label="Permalink to &quot;メニュー変更が反映されない&quot;">​</a></h3><p>管理ダッシュボードでメニューを変更した後、各画面への反映タイミングは以下のとおりです。</p><table tabindex="0"><thead><tr><th>画面</th><th>反映タイミング</th></tr></thead><tbody><tr><td>セルフオーダー</td><td>メニューバージョンチェック（3分間隔）またはページリロード</td></tr><tr><td>ハンディPOS</td><td>メニューバージョンチェック（3分間隔）</td></tr><tr><td>KDS</td><td>次の注文受信時</td></tr></tbody></table><p>急ぎの場合は、各画面でブラウザをリロード（F5）してください。</p><hr><h2 id="_19-7-シフト関連" tabindex="-1">19.7 シフト関連 <a class="header-anchor" href="#_19-7-シフト関連" aria-label="Permalink to &quot;19.7 シフト関連&quot;">​</a></h2><h3 id="gps打刻でエラーが出る" tabindex="-1">GPS打刻でエラーが出る <a class="header-anchor" href="#gps打刻でエラーが出る" aria-label="Permalink to &quot;GPS打刻でエラーが出る&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>位置情報の許可エラー</td><td>ブラウザの位置情報が無効</td><td>ブラウザの設定で位置情報を許可する</td></tr><tr><td>距離エラー</td><td>店舗から離れすぎている</td><td>店舗の許容半径内（シフト設定で確認）に移動してから打刻</td></tr><tr><td>「既に出勤中です」</td><td>二重打刻</td><td>前回の退勤打刻ができていない。マネージャーに確認</td></tr></tbody></table><hr><h2 id="_19-8-推奨環境の確認" tabindex="-1">19.8 推奨環境の確認 <a class="header-anchor" href="#_19-8-推奨環境の確認" aria-label="Permalink to &quot;19.8 推奨環境の確認&quot;">​</a></h2><p>問題が解決しない場合、以下の環境を確認してください。</p><table tabindex="0"><thead><tr><th>項目</th><th>推奨</th></tr></thead><tbody><tr><td>ブラウザ</td><td>Google Chrome（最新版）推奨</td></tr><tr><td>管理ダッシュボード</td><td>PC/タブレット（10インチ以上）</td></tr><tr><td>KDS</td><td>タブレット（10インチ以上、横置き）</td></tr><tr><td>ハンディPOS</td><td>スマートフォン（5〜8インチ）</td></tr><tr><td>インターネット</td><td>安定した接続（Wi-Fi推奨、有線LANがベスト）</td></tr></tbody></table><hr><h2 id="_19-9-posla運営への問い合わせ" tabindex="-1">19.9 POSLA運営への問い合わせ <a class="header-anchor" href="#_19-9-posla運営への問い合わせ" aria-label="Permalink to &quot;19.9 POSLA運営への問い合わせ&quot;">​</a></h2><p>上記で解決しない場合は、POSLA運営（プラスビリーフ）にお問い合わせください。</p><p>問い合わせ時に以下の情報をお伝えいただくと、迅速な対応が可能です。</p><ul><li>テナント名・店舗名</li><li>問題が発生した日時</li><li>問題の症状（エラーメッセージがあれば正確に）</li><li>使用しているブラウザとOS</li><li>問題が発生する画面（管理ダッシュボード/KDS/ハンディPOS/セルフオーダー等）</li></ul>',51)])])}const q=d(h,[["render",l]]);export{c as __pageData,q as default};
